const {
  default: makeWASocket,
  useMultiFileAuthState,
  fetchLatestBaileysVersion,
  DisconnectReason
} = require("baileys");
const P = require("pino");
const fs = require("fs");
const http = require("http");

const SESSION_DIR = process.env.SESSION_DIR || "./auth_info";
let sock;
let isStarting = false;

async function startBot() {
  if (isStarting) return;
  isStarting = true;

  try {
    if (!fs.existsSync(SESSION_DIR)) {
      fs.mkdirSync(SESSION_DIR, { recursive: true });
    }

    const { state, saveCreds } = await useMultiFileAuthState(SESSION_DIR);
    const { version } = await fetchLatestBaileysVersion();

    sock = makeWASocket({
      version,
      logger: P({ level: "silent" }),
      auth: state,
      printQRInTerminal: true,
      browser: ["Railway Bot", "Chrome", "1.0.0"]
    });

    sock.ev.on("creds.update", saveCreds);

    sock.ev.on("connection.update", async (update) => {
      const { connection, lastDisconnect } = update;

      if (connection === "open") {
        console.log("WhatsApp bot connected");
      }

      if (connection === "close") {
        const statusCode = lastDisconnect?.error?.output?.statusCode;
        const shouldReconnect = statusCode !== DisconnectReason.loggedOut;

        console.log("Connection closed. Reconnect:", shouldReconnect);

        if (shouldReconnect) {
          setTimeout(() => {
            isStarting = false;
            startBot();
          }, 5000);
        }
      }
    });

    sock.ev.on("messages.upsert", async ({ messages, type }) => {
      if (type !== "notify") return;

      const msg = messages[0];
      if (!msg || !msg.message) return;

      const jid = msg.key.remoteJid;
      const text =
        msg.message.conversation ||
        msg.message.extendedTextMessage?.text ||
        "";

      console.log("Pesan masuk:", jid, text, "fromMe:", msg.key.fromMe);

      // Untuk tes, jangan skip fromMe dulu
      if (text.toLowerCase() === "ping") {
        await sock.sendMessage(jid, { text: "pong" });
      } else if (text.toLowerCase() === "halo") {
        await sock.sendMessage(jid, { text: "Halo juga 👋" });
      }
    });
  } catch (err) {
    console.error("Start bot error:", err);
  } finally {
    isStarting = false;
  }
}

const PORT = process.env.PORT || 3000;
http.createServer((req, res) => {
  res.writeHead(200, { "Content-Type": "text/plain; charset=utf-8" });
  res.end("WhatsApp bot Railway aktif");
}).listen(PORT, "0.0.0.0", () => {
  console.log(`HTTP server aktif di ${PORT}`);
});

startBot();